Image(systemName: "globe")
    .onAppear {
        print("This is the debug output.")
    }

extension View {
    func printOutput(_ value: Any) -> Self {
        print(value)
        return self
    }
}

VStack {
   ForEach(colors, id: \.self) { color in
      Circle()
         .foregroundColor(color)
         .printOutput(color)
   }
}

var body: some View {
    let _ = Self._printChanges()
